ControlPropertyState.AutoRuleBindingString:
// 1. Check if mandatory fields are filled
If(
    IsBlank(txtEmail.Value) || IsBlank(ddRoles.Selected) || IsBlank(ddDepartments.Selected),

    // IF INVALID: Show warning
    Notify("Please fill in all mandatory fields (Email, Role, and Department).", NotificationType.Warning);
    UpdateContext({isPopupConfirm: false});,

    // IF VALID: Proceed with Patch
    UpdateContext({ varIsLoading: true }); // Optional: trigger your spinning icon

    IfError(
        Patch(
            tbl_mrl_users,
            Defaults(tbl_mrl_users),
            {
                email: Trim(txtEmail.Value),
                // Staff ID is patched only if not blank, otherwise sends blank
                mrl_employee_id: If(!IsBlank(txtStaffID.Value), Trim(txtStaffID.Value), Blank()),
                role: { 
                    Id: ddRoles.Selected.ID, 
                    Value: ddRoles.Selected.role_name 
                },
                department: { 
                    Id: ddDepartments.Selected.ID, 
                    Value: ddDepartments.Selected.department_code 
                },
                status: { 
                    Id: 1, 
                    Value: "Active" 
                }
            }
        ),

        // Error Handling
        Notify("Error: Could not create user. The email might already exist.", NotificationType.Error),

        // Success Actions
        Notify("User account '" & varTempuserName & "' created successfully.", NotificationType.Success);

        // Clean up UI
        Reset(txtEmail);
        Reset(txtName);
        Reset(txtStaffID);
        Reset(ddRoles);
        Reset(ddDepartments);

        UpdateContext({
            isPopupNewUser: false,
            isPopupConfirm: false,
            varTempuserName: Blank(),
            varIsLoading: false
        })
    )
)

// 1. Check if mandatory fields are filled
If(
    IsBlank(txtVuEmail.Text) || IsBlank(ddVuRole.Selected) || IsBlank(ddVuDepartment.Selected),

    // IF INVALID: Show warning
    Notify("Please fill in all mandatory fields (Email, Role, and Department).", NotificationType.Warning);
    UpdateContext({ispopupVuConfirm: false});,

    // IF VALID: Proceed with Patch
    UpdateContext({ varIsLoading: true }); // Optional: trigger your spinning icon

    IfError(
        Patch(
            tbl_mrl_users,
            LookUp(tbl_mrl_users, ID = varSelectedUser.ID),
            {
                email: Trim(txtVuEmail.Text),
                // Staff ID is patched only if not blank, otherwise sends blank
                mrl_employee_id: If(!IsBlank(txtVuStaffID.Text), Trim(txtVuStaffID.Text), Blank()),
                role: { 
                    Id: ddVuRole.Selected.ID, 
                    Value: ddVuRole.Selected.role_name 
                },
                department: { 
                    Id: ddVuDepartment.Selected.ID, 
                    Value: ddVuDepartment.Selected.department_code 
                },
                status: { 
                    Id: ddVuStatus.Selected.ID, 
                    Value: ddVuStatus.Selected.status_name 
                }
            }
        ),

        // Error Handling
        Notify("Error: Could not create user. The email might already exist.", NotificationType.Error),

        // Success Actions
        Notify("User account '" & txtVuEmail.Text & "' created successfully.", NotificationType.Success);

        // Clean up UI

        UpdateContext({
            ispopupVuConfirm: false,
            varIsLoading: false
        })
    )
)
